pub inline fn compatibilityDecomposeRaw(cp: CodePoint) ?[]const CodePoint {
    if (cp > 0x10FFFF) return null;
    const page = compat_decomp_level1[cp >> 8];
    const idx = compat_decomp_level2[page][cp & 0xFF];
    if (idx == 0) return null;
    return compat_decomp_mappings[idx];
}

